    19→	constructor(
    20→		private readonly relatedProductsService: RelatedProductsService,
    21→		private readonly metricsService: MetricsService,
    22→	) {}
    23→
    24→	@Get('brand')
    25→	@ApiOperation({ summary: 'Get products for a specific brand' })
    26→	@ApiResponse({
    27→		status: 200,
    28→		description: 'Returns products for the specified brand',
    29→		type: BrandProductsResponseDto,
    30→	})
    31→	@ApiResponse({ status: 404, description: 'Brand not found' })
    32→	@ApiResponse({ status: 500, description: 'Internal server error' })
    33→	async getBrandProducts(
    34→		@Query() query: BrandProductsQueryDto,
    35→	): Promise<BrandProductsResponseDto> {
    36→		return await this.relatedProductsService.getBrandProducts(query);
    37→	}
    38→
    39→	@Get(':productId')
    40→	@ApiOperation({ summary: 'Get related products for a specific product ID' })
    41→	@ApiParam({ name: 'productId', type: String, description: 'Product ID' })
    42→	@ApiResponse({
    43→		status: 200,
    44→		description: 'Returns related products for the specified product ID',
    45→		type: RelatedProductsResponseDto,
    46→	})
    47→	@ApiResponse({ status: 404, description: 'Product not found' })
    48→	@ApiResponse({ status: 500, description: 'Internal server error' })
    49→	@LogExecution({
    50→		paramFormatter: (params: [string, RelatedProductsQueryDto]) => ({
    51→			productId: params[0],
    52→			query: params[1],
    53→		}),
    54→		responseFormatter: (response: RelatedProductsResponseDto) => ({
    55→			relatedProducts: response.related_products.length,
    56→			productId: response.product_id,
    57→			mmsFallback: response.mms_fallback,
    58→			colorId: response.color_id,
    59→		}),
    60→	})
    61→	async getRelatedProducts(
    62→		@Param('productId') productId: string,
    63→		@Query() query: RelatedProductsQueryDto,
    64→	): Promise<RelatedProductsResponseDto> {
    65→		await this.metricsService.incrementDailyCounter(
    66→			dailyTrackingKeys.RELATED_PRODUCTS_REQUESTS,
    67→		);
    68→		return this.relatedProductsService.getRelatedProducts(productId, query);
    69→	}
    70→}
