     1→import { Inject, Injectable, Logger } from '@nestjs/common';
     2→import { Redis } from 'ioredis';
     3→import Keyv from 'keyv';
     4→import Redlock, { Lock } from 'redlock';
     5→
     6→import {
     7→	REDIS_WRITE_CLIENT,
     8→	REDIS_READ_CLIENT,
     9→	CACHE_WRITE_MANAGER,
    10→	CACHE_READ_MANAGER,
    11→} from '@constants/common.constant';
    12→
    13→import { Namespaces } from '@interfaces/cache.interface';
    14→
    15→import { LogExecution } from '@decorators/log-execution.decorator';
    16→
    17→export enum ConsistencyLevel {
    18→	EVENTUAL = 'eventual',
    19→	STRONG = 'strong',
    20→}
    21→
    22→export interface CacheError extends Error {
    23→	code: 'CONNECTION_FAILED' | 'KEY_NOT_FOUND' | 'OPERATION_FAILED';
    24→	originalError?: Error;
    25→}
    26→
    27→@Injectable()
    28→export class CacheService {
    29→	private readonly logger = new Logger(CacheService.name);
    30→	private readonly redlock: Redlock;
    31→	private readonly redisWriteClient: Redis;
    32→	private readonly redisReadClient: Redis;
    33→	private readonly cacheWriteManager: Keyv;
    34→	private readonly cacheReadManager: Keyv;
    35→	private readonly recentWrites = new Map<string, number>();
    36→	private readonly CONSISTENCY_WINDOW_MS = 1000;
    37→	private isReadReplicaHealthy = true;
    38→
    39→	constructor(
    40→		@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
    41→		@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
    42→		@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
    43→		@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
    44→	) {
    45→		this.cacheWriteManager = cacheWriteManager;
    46→		this.cacheReadManager = cacheReadManager;
    47→		this.redisWriteClient = redisWriteClient;
    48→		this.redisReadClient = redisReadClient;
    49→		this.redlock = new Redlock([redisWriteClient], {
    50→			driftFactor: 0.01,
    51→			retryCount: 10,
    52→			retryDelay: 200,
    53→			retryJitter: 200,
    54→		});
    55→
    56→		this.setupHealthChecks();
    57→		this.startRecentWritesCleanup();
    58→	}
    59→
    60→	@LogExecution({
    61→		paramFormatter: (params) => params,
    62→		responseFormatter: () => '',
    63→	})
    64→	async get<T>({
    65→		namespace,
    66→		key,
    67→		consistency = ConsistencyLevel.EVENTUAL,
    68→	}: {
    69→		namespace: Namespaces;
    70→		key: string;
    71→		consistency?: ConsistencyLevel;
    72→	}): Promise<T | null> {
    73→		const namespacedKey = this.getNamespacedKey({ namespace, key });
    74→
    75→		const shouldReadFromMaster = this.shouldReadFromMaster(namespacedKey, consistency);
    76→		const cacheManager = shouldReadFromMaster
    77→			? this.cacheWriteManager
    78→			: this.cacheReadManager;
    79→		const source = shouldReadFromMaster ? 'master' : 'replica';
    80→
    81→		try {
    82→			const result = (await cacheManager.get(namespacedKey)) as T;
    83→
    84→			if (!result) {
    85→				this.logger.log('Cache miss', { namespace, key, consistency, source });
    86→				return null;
    87→			}
    88→
    89→			this.logger.log('Cache hit', { namespace, key });
    90→
    91→			return result;
    92→		} catch (error) {
    93→			const e = error as Error;
    94→			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
    95→
    96→			if (!shouldReadFromMaster && this.isReadReplicaHealthy) {
    97→				this.logger.warn('Read replica failed, falling back to master', {
    98→					namespace,
    99→					key,
   100→				});
   101→				this.isReadReplicaHealthy = false;
   102→				return this.get({ namespace, key, consistency: ConsistencyLevel.STRONG });
   103→			}
   104→
   105→			throw this.createCacheError('CONNECTION_FAILED', e);
   106→		}
   107→	}
   108→
   109→	@LogExecution({
   110→		paramFormatter: (params: {
   111→			namespace: Namespaces;
   112→			key: string;
   113→			value: unknown;
   114→			ttl?: number;
   115→		}) => ({
   116→			namespace: params.namespace,
   117→			key: params.key,
   118→			value: '***',
   119→			ttl: params.ttl,
   120→		}),
   121→		responseFormatter: () => '',
   122→	})
   123→	async set<T>({
   124→		namespace,
   125→		key,
   126→		value,
   127→		ttl,
   128→	}: {
   129→		namespace: Namespaces;
   130→		key: string;
   131→		value: T;
   132→		ttl?: number;
   133→	}): Promise<void> {
   134→		const namespacedKey = this.getNamespacedKey({ namespace, key });
   135→
   136→		try {
   137→			await this.cacheWriteManager.set(namespacedKey, value, ttl);
   138→			this.trackRecentWrite(namespacedKey);
   139→			this.logger.log('Cached value', { namespace, key, ttl });
   140→		} catch (error) {
   141→			const e = error as Error;
   142→			this.logger.error(`Error setting cache: ${e.message}`, e.stack);
   143→			throw this.createCacheError('OPERATION_FAILED', e);
   144→		}
   145→	}
   146→
   147→	@LogExecution({
   148→		paramFormatter: (params) => params,
   149→		responseFormatter: (res) => (res ? 'true' : 'false'),
   150→	})
   151→	async has({
   152→		namespace,
   153→		key,
   154→	}: {
   155→		namespace: Namespaces;
   156→		key: string;
   157→	}): Promise<boolean> {
   158→		this.logger.log('Checking cache key existence', { namespace, key });
   159→		const value = await this.get<unknown>({ namespace, key });
   160→		return value !== null;
   161→	}
   162→
   163→	@LogExecution({
   164→		paramFormatter: (params) => params,
   165→		responseFormatter: (res) => (res ? 'true' : 'false'),
   166→	})
   167→	async deleteOne({
   168→		namespace,
   169→		key,
   170→	}: {
   171→		namespace: Namespaces;
   172→		key: string;
   173→	}): Promise<boolean> {
   174→		try {
   175→			const namespacedKey = this.getNamespacedKey({ namespace, key });
   176→			await this.cacheWriteManager.delete(namespacedKey);
   177→			this.logger.log('Deleted cache key', { namespace, key });
   178→			return true;
   179→		} catch (error) {
   180→			const e = error as Error;
   181→			this.logger.error(`Error deleting from cache: ${e.message}`, e.stack);
   182→			return false;
   183→		}
   184→	}
   185→
   186→	async incrementByOne({
   187→		namespace,
   188→		key,
   189→	}: {
   190→		namespace: Namespaces;
   191→		key: string;
   192→	}): Promise<void> {
   193→		try {
   194→			const namespacedKey = this.getNamespacedKey({ namespace, key });
   195→			await this.redisWriteClient.incr(namespacedKey);
   196→		} catch (error) {
   197→			const e = error as Error;
   198→			this.logger.error(`Error incrementing cache key: ${e.message}`, e.stack, {
   199→				namespace,
   200→				key,
   201→			});
   202→			throw error;
   203→		}
   204→	}
   205→
   206→	async deleteAll(): Promise<boolean> {
   207→		try {
   208→			await this.cacheWriteManager.clear();
   209→
   210→			await new Promise((resolve) => setTimeout(resolve, 100));
   211→
   212→			await this.cacheReadManager.clear();
   213→			this.recentWrites.clear();
   214→			this.logger.log('Cleared all cache');
   215→			return true;
   216→		} catch (error) {
   217→			const e = error as Error;
   218→			this.logger.error(`Error clearing cache: ${e.message}`, e.stack);
   219→			return false;
   220→		}
   221→	}
