### 1. **REST Controller Pattern** (Example: Related Products)

**File:** `/Users/4thwithme/Documents/repo/recommendations-service/src/modules/rest/related-products/related-products.controller.ts`

**Key Pattern:**
```typescript
@ApiTags('Related Products')
@Controller('related-products')
export class RelatedProductsController {
  constructor(
    private readonly relatedProductsService: RelatedProductsService,
    private readonly metricsService: MetricsService,
  ) {}

  @Get(':productId')
  @ApiOperation({ summary: 'Get related products for a specific product ID' })
  @ApiParam({ name: 'productId', type: String, description: 'Product ID' })
  @ApiResponse({
    status: 200,
    description: 'Returns related products...',
    type: RelatedProductsResponseDto,
  })
  @ApiResponse({ status: 404, description: 'Product not found' })
  @LogExecution({
    paramFormatter: (params: [string, RelatedProductsQueryDto]) => ({
      productId: params[0],
      query: params[1],
    }),
    responseFormatter: (response: RelatedProductsResponseDto) => ({
      relatedProducts: response.related_products.length,
      productId: response.product_id,
      mmsFallback: response.mms_fallback,
      colorId: response.color_id,
    }),
  })
  async getRelatedProducts(
    @Param('productId') productId: string,
    @Query() query: RelatedProductsQueryDto,
  ): Promise<RelatedProductsResponseDto> {
    await this.metricsService.incrementDailyCounter(dailyTrackingKeys.RELATED_PRODUCTS_REQUESTS);
    return this.relatedProductsService.getRelatedProducts(productId, query);
  }
}
```

**Decorator Pattern Breakdown:**
- `@ApiTags()` - Groups endpoints in Swagger UI
- `@ApiOperation()` - Endpoint description
- `@ApiParam()` / `@ApiResponse()` - Swagger documentation
- `@LogExecution()` - Wraps with paramFormatter & responseFormatter to log execution metrics
- `@Param()` / `@Query()` - NestJS decorators for route params and query strings
- Custom formatters: Only log relevant parts (not full responses for large payloads)

---

### 2. **REST Service with Caching (Redis)** (Example: Addons Service)

**File:** `/Users/4thwithme/Documents/repo/recommendations-service/src/modules/rest/addons/addons.service.ts`

**Cache Key Pattern:**
```typescript
@Injectable()
export class AddonsService implements OnModuleInit {
  private readonly logger = new Logger(AddonsService.name);
  private curatedAddonsCacheTtl: number;
  private readonly cacheKey = 'curated-addons';  // Simple cache key

  constructor(
    private readonly cacheService: CacheService,
    private readonly configService: EnvConfigService,
    private readonly productHydrationService: ProductHydrationService,
    private readonly stylesService: StylesService,
  ) {}

  onModuleInit(): void {
    this.curatedAddonsCacheTtl = this.configService.get<number>({
      key: CURATED_ADDONS_CACHE_TTL,
      converter: Number,
    });
  }

  @LogExecution({
    paramFormatter: (params) => params,
    responseFormatter: (response: AddonsCuratedResponseDto) => response.addons.length,
  })
  async getCuratedAddons(): Promise<AddonsCuratedResponseDto> {
    try {
      // Try to get from cache first
      const cachedData = await this.cacheService.get<AddonsCuratedResponseDto>({
        namespace: Namespaces.CURATED_ADDONS,
        key: this.cacheKey,
      });

      if (cachedData) {
        this.logger.log('Cache hit for curated addons', {
          cacheKey: this.cacheKey,
          count: cachedData.addons.length,
        });
        return { addons: shuffleArray(cachedData.addons) };
      }

      // Cache miss - fetch data
      this.logger.log('Cache miss for curated addons', { cacheKey: this.cacheKey });
      const styleIds = this.curatedAddonsIds.map((id) => Number(id));
      const stylesInStock = await this.stylesService.getStylesInStockByIds({ styleIds });

      if (stylesInStock.length === 0) {
        throw new NotFoundException('No curated addons products found in stock');
      }

      const eligibleStyleIds = stylesInStock.map((style) => style.style_id);
      const { products, mvRecords } = 
        await this.productHydrationService.hydrateProductsWithColors({ styleIds: eligibleStyleIds });

      const addons = products.map((product) => {
        const mvRecord = mvRecords.get(product.style_id);
        const colors = this.productHydrationService.convertMvColorsToProductColors(
          mvRecord?.colors ?? null,
        );
        return assignRandomColorToProduct(product, colors);
      });

      const result = { addons };

      // Set cache with TTL
      await this.cacheService.set({
        namespace: Namespaces.CURATED_ADDONS,
        key: this.cacheKey,
        value: result,
        ttl: this.curatedAddonsCacheTtl,
      });

      return { addons: shuffleArray(result.addons) };
    } catch (error) {
      if (error instanceof NotFoundException) throw error;
      const err = error instanceof Error ? error : new Error(String(error));
      this.logger.error(`Error fetching curated addons: ${err.message}`, err.stack);
      throw err;
    }
  }
}
```

**Cache Service Usage Pattern:**
- **Interface:** `CacheService` (from `@modules/cache/cache.service.ts`)
- **Methods:**
  - `get<T>({ namespace, key, consistency? })` - Retrieve from cache
  - `set({ namespace, key, value, ttl? })` - Store in cache with TTL
  - `delete({ namespace, key })` - Remove cache entry
  - `withLock({ lockKey, operation, ttl })` - Distributed locking

- **Namespaces** (from `/src/interfaces/cache.interface.ts`):
  ```typescript
  enum Namespaces {
    RELATED_ITEMS_MODEL = 'related-items-model',
    FBT_MODEL = 'fbt-model',
    MMS_COMPLEMENTS = 'mms-complements',
    MMS_ALTERNATIVES = 'mms-alternatives',
    HEALTH_CHECK = 'health-check',
    METRICS = 'metrics',
    CURATED_ADDONS = 'curated-addons',
  }
  ```

- **TTL Configuration:**
  - Loaded from env via `EnvConfigService`
  - Example: `CURATED_ADDONS_CACHE_TTL` (env variable)
  - Passed to `cacheService.set()` as milliseconds
  - Namespaced key format: `{namespace}:{key}` (e.g., `curated-addons:curated-addons`)

